SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- Workflow template seed data required by /workflow/model/initStart.
-- Keep this file separate from oortcloud_workflowforms_initialize.sql so table structure can be re-exported safely.

-- Records of ACT_GE_BYTEARRAY
-- 7 rows

-- Records of ACT_RE_MODEL
-- 7 rows

-- Records of re_model_json
-- 7 rows

-- Records of process_template
-- 7 rows

-- Records of wf_form_synthesis
-- 1 rows

-- Records of wf_form
-- 6 rows

-- Normalize the public system-approval form seed to the fixed root tenant.
-- This keeps the seed usable even if the source database exported these forms from another tenant.
UPDATE `wf_form_synthesis`
SET `tenant_id` = '0e391fd7-1033-4f09-88c0-187582fee462'
WHERE `tenant_id` IN ('24cdafd7-528a-4514-92ff-76f474fb8781', '0b3c0131-f4be-11ef-8496-6cf6da435cd3')
  AND `category_name` = '系统审批'
  AND COALESCE(`type`, '') = '0'
  AND COALESCE(`del_flag`, '0') = '0';

UPDATE `wf_form`
SET `tenant_id` = '0e391fd7-1033-4f09-88c0-187582fee462'
WHERE `tenant_id` IN ('24cdafd7-528a-4514-92ff-76f474fb8781', '0b3c0131-f4be-11ef-8496-6cf6da435cd3')
  AND `category_id` = '1971042914271039489'
  AND COALESCE(`type`, '') = '0'
  AND `form_name` IN ('租户审批', '企业主体审批', '部门审批', '用户审批', '用户权限提升申请审批', '租户认证审批');

SET FOREIGN_KEY_CHECKS = 1;
